import{_ as a,c as i,S as o,o as t}from"./chunks/framework.BjmDYXuv.js";const g=JSON.parse('{"title":"Changelog","description":"","frontmatter":{},"headers":[],"relativePath":"changelog.md","filePath":"changelog.md","lastUpdated":1775818564000}'),d={name:"changelog.md"};function l(r,e,s,c,n,h){return t(),i("div",null,e[0]||(e[0]=[o('<h1 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h1><p>All notable changes to this project will be documented in this file.</p><p>The format is based on Keep a Changelog, and this project adheres to Semantic Versioning.</p><h2 id="_0-4-0-2026-04-09" tabindex="-1">[0.4.0] - 2026-04-09 <a class="header-anchor" href="#_0-4-0-2026-04-09" aria-label="Permalink to &quot;[0.4.0] - 2026-04-09&quot;">​</a></h2><h3 id="added" tabindex="-1">Added <a class="header-anchor" href="#added" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>[library] Top-level <code>colliderml.load(dataset, *, tables, max_events, event_range, …)</code> — a one-liner that downloads missing parquets on demand, then loads them with the existing Polars backend. Uses the same <code>&lt;channel&gt;_&lt;pileup&gt;</code> shorthand as the benchmark task runner.</li><li>[library] <code>colliderml.simulate</code> subpackage — run the full Pythia / MadGraph / Geant4 / ACTS pipeline locally inside a Docker or Podman container, or submit to the SaaS backend with <code>remote=True</code>. Local simulate auto-clones the companion <code>colliderml-production</code> repo at a pinned git ref for pipeline scripts, mirroring the existing ODD and MG5aMC_PY8_interface cache pattern. Ships a bundled preset catalogue (<code>ttbar-quick</code>, <code>higgs-portal-quick</code>, <code>ttbar-dev</code>, <code>ttbar-benchmark</code>, …) accessible via <code>colliderml.simulate.load_presets()</code>.</li><li>[library] <code>colliderml.remote</code> subpackage — HTTP client for the ColliderML SaaS backend service. Exposes <code>submit</code>, <code>status</code>, <code>wait_for</code>, <code>get_me</code>, <code>balance</code>, and a <code>RemoteSubmission</code> dataclass. Authentication is via a HuggingFace token resolved from the environment or the hub&#39;s saved credentials.</li><li>[library] <code>colliderml.tasks</code> subpackage — registry and runner for six benchmark tasks: <code>tracking</code>, <code>jets</code>, <code>anomaly</code>, <code>tracking_latency</code>, <code>tracking_small</code>, <code>data_loading</code>. Each task defines a dataset, eval event range, input tables, metrics, and a <code>higher_is_better</code> direction. Reference baselines (CKF for tracking, scikit-learn GBDT for jets, IsolationForest for anomaly detection) run as <code>python -m colliderml.tasks.&lt;task&gt;.baselines.&lt;name&gt;</code>.</li><li>[library] CLI subcommands: <code>simulate</code>, <code>list-presets</code>, <code>balance</code>, <code>status</code>. Each handler lazily imports its subsystem so existing <code>download</code> / <code>list-configs</code> commands stay fast.</li><li>[library] Optional extras: <code>[sim]</code>, <code>[remote]</code>, <code>[tasks]</code>, and an <code>[all]</code> meta-extra that bundles everything plus <code>[dev]</code>. Base install stays lean.</li><li>[library] <code>pyarrow&gt;=14.0.0</code> added to <code>install_requires</code> (used by the task scoring code at the polars/arrow boundary).</li><li>[docs] New guide pages: <code>guide/simulation</code>, <code>guide/remote-simulation</code>, <code>guide/tasks</code>. New library reference pages: <code>library/simulate</code>, <code>library/remote</code>, <code>library/tasks</code>. Navigation and sidebar extended to surface the new content.</li><li>[docs] Installation page documents the new optional extras with prerequisites.</li><li>[docs] Quickstart and library overview pages extended with simulate + tasks examples.</li><li>[infra] <code>docs/.vitepress/config.ts</code> reads <code>VITEPRESS_BASE</code> from the environment so the same config builds both the canonical <code>/ColliderML/</code> site and a <code>/ColliderML/staging/</code> preview (infrastructure landing in a sibling commit; see B7).</li></ul><h3 id="changed" tabindex="-1">Changed <a class="header-anchor" href="#changed" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li>[library] Top-level <code>colliderml</code> package now uses a <code>__getattr__</code> lazy loader for the optional <code>simulate</code>, <code>remote</code>, and <code>tasks</code> subsystems so <code>import colliderml</code> stays cheap when extras aren&#39;t installed.</li></ul><h2 id="_0-3-0-2025-12-19" tabindex="-1">[0.3.0] - 2025-12-19 <a class="header-anchor" href="#_0-3-0-2025-12-19" aria-label="Permalink to &quot;[0.3.0] - 2025-12-19&quot;">​</a></h2><h3 id="added-1" tabindex="-1">Added <a class="header-anchor" href="#added-1" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>[library] CLI commands: <code>colliderml download</code> for downloading HuggingFace datasets with local caching, <code>colliderml list-configs</code> for discovering available configurations.</li><li>[library] Polars-based data loader with lazy/eager loading support and structured configuration (YAML/dict).</li><li>[library] Physics utilities: pileup subsampling, decay-chain traversal with primary ancestor assignment, calorimeter calibration with region-specific scaling factors.</li><li>[library] Flattening helpers to explode nested Parquet structures into pandas DataFrames for analysis.</li><li>[library] Visualization utilities: coordinate transformations (eta, r), binned energy profile plotting.</li><li>[library] Download timing benchmarks integrated into CI/CD.</li><li>[docs] Reference exploration notebook demonstrating loader, physics utilities, and visualization.</li></ul><h3 id="changed-1" tabindex="-1">Changed <a class="header-anchor" href="#changed-1" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li>[library] Data loading now uses local Parquet cache populated by CLI, not direct HuggingFace streaming.</li><li>[library] Exploded/flattened data structures now return pandas DataFrames for downstream analysis.</li><li>[library] Physics constants (calorimeter calibration factors) centralized in <code>colliderml.physics.constants</code>.</li></ul><h3 id="fixed" tabindex="-1">Fixed <a class="header-anchor" href="#fixed" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>[library] Decay traversal now correctly identifies root particles by broken parent links, ignoring the <code>primary</code> flag.</li><li>[library] Pileup subsampling now correctly filters tracker hits and calorimeter contributions by particle ID.</li><li>[library] Calorimeter calibration now handles both region names and raw detector IDs.</li></ul><h2 id="_0-2-0-2025-11-07" tabindex="-1">[0.2.0] - 2025-11-07 <a class="header-anchor" href="#_0-2-0-2025-11-07" aria-label="Permalink to &quot;[0.2.0] - 2025-11-07&quot;">​</a></h2><h3 id="added-2" tabindex="-1">Added <a class="header-anchor" href="#added-2" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>[dataset] Datasets now hosted on HuggingFace Hub for easier access and distribution.</li><li>[dataset] Support for standard HuggingFace <code>datasets</code> library for data loading.</li><li>[docs] Interactive dataset configurator with dynamic channel discovery from HuggingFace API.</li><li>[docs] Updated documentation site with HuggingFace integration examples.</li></ul><h3 id="changed-2" tabindex="-1">Changed <a class="header-anchor" href="#changed-2" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li>[dataset] Migrated from NERSC manifest-based distribution to HuggingFace datasets.</li><li>[dataset] Data now stored in Parquet format with improved compression and accessibility.</li><li>[docs] Simplified data access workflow using <code>load_dataset()</code> instead of custom CLI.</li></ul><h3 id="removed" tabindex="-1">Removed <a class="header-anchor" href="#removed" aria-label="Permalink to &quot;Removed&quot;">​</a></h3><ul><li>[docs] Removed NERSC manifest.json dependency from documentation build process.</li></ul><h2 id="_0-1-0-2025-09-08" tabindex="-1">[0.1.0] - 2025-09-08 <a class="header-anchor" href="#_0-1-0-2025-09-08" aria-label="Permalink to &quot;[0.1.0] - 2025-09-08&quot;">​</a></h2><h3 id="added-3" tabindex="-1">Added <a class="header-anchor" href="#added-3" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>[dataset] Initial release of ColliderML dataset with ttbar and ggf physics processes.</li><li>[dataset] Four detector hierarchy levels: particles, tracker_hits, calo_hits, and tracks.</li><li>[dataset] Approximately 100,000 simulated events per process with no pileup (pu0).</li><li>[library] Initial <code>colliderml</code> Python library with data access utilities.</li><li>[docs] Documentation website with VitePress framework.</li><li>[docs] Dataset configuration modal for exploring available data.</li></ul><hr><p>Unreleased changes should be added under a <code>## [Unreleased]</code> header above with entries marked as <code>[dataset]</code>, <code>[library]</code>, or <code>[docs]</code>.</p>',27)]))}const m=a(d,[["render",l]]);export{g as __pageData,m as default};
